from crewai import Task
from vex_sdk import VexClient

vex = VexClient(api_key='your-vex-key')

def aml_guardrail(task_output):
    # Extract transaction data
    transactions = vex.parse_transactions(task_output)

    # Run AML screening
    risks = vex.screen_aml({
        'transactions': transactions,
        'threshold': 'high_risk',
        'customer_profile': 'fintech_user'
    })

    if risks['suspicious_activity']:
        vex.alert_regulator(risks)
        return {'blocked': True, 'reason': risks['flags']}

    # Add disclaimer for approved transactions
    return {
        'approved': True,
        'output': task_output + '\n\nDISCLAIMER: Not financial advice. Consult licensed professional.',
        'risk_score': risks['score']
    }

payment_task = Task(
    description='Process customer payment...',
    agent=payment_agent,
    output_callback=aml_guardrail
)
